// Đổi link ngắn ?p=<path trong bucket> thành link XEM TRỰC TIẾP:
// - excel/word/powerpoint -> Office Viewer (xem ngay trên điện thoại, không phải tải về;
//   giới hạn của Office Viewer: file ~10MB trở xuống)
// - pdf / video / ảnh     -> mở thẳng URL Storage, trình duyệt tự render
// Path phải nằm trong bucket task-attachments (chặn '..' để không trỏ đi nơi khác).
const q = $input.first().json.query || {};
const p = String(q.p || '');
const BUCKET_BASE = 'https://ngwkzicrnspeggunsblr.supabase.co/storage/v1/object/public/task-attachments/';
const FALLBACK = 'https://amazing-frangollo-eb56a9.netlify.app';

let target = FALLBACK;
if (p && !p.includes('..')) {
    const raw = BUCKET_BASE + p;
    const m = p.toLowerCase().match(/\.([a-z0-9]+)$/);
    const ext = m ? m[1] : '';
    target = ['xlsx', 'xls', 'docx', 'doc', 'pptx', 'ppt'].includes(ext)
        ? 'https://view.officeapps.live.com/op/view.aspx?src=' + encodeURIComponent(raw)
        : raw;
}
return [{ json: { target } }];
